                teams[team2]['bo1_wins'] += 1; teams[team1]['bo1_losses'] += 1
        elif match_type == 3:
            if team1_wins > team2_wins:
                teams[team1]['bo3_wins'] += 1; teams[team2]['bo3_losses'] += 1
            else:
                teams[team2]['bo3_wins'] += 1; teams[team1]['bo3_losses'] += 1
        elif match_type == 5:
            if team1_wins > team2_wins:
                teams[team1]['bo5_wins'] += 1; teams[team2]['bo5_losses'] += 1
            else:
                teams[team2]['bo5_wins'] += 1; teams[team1]['bo5_losses'] += 1

        if team1_wins > team2_wins:
            teams[team1]['win_streaks'].append(1); teams[team2]['win_streaks'].append(0)
        else:
            teams[team2]['win_streaks'].append(1); teams[team1]['win_streaks'].append(0)

    for team in teams.values():
        streak = 0
        for win in team['win_streaks']:
            if win:
                streak += 1
            else:
                if streak >= 3:
                    team['win_streaks_count'].append(streak)
                streak = 0
        if streak >= 3:
            team['win_streaks_count'].append(streak)

    return {
        'date': (year, month, day),
        'num_teams': n,
        'teams': teams,
        'competition_level': competition_level,
        'matches': matches,
        'x': x
    }


def calculate_first_integral(data):
    teams = data['teams']
    n = data['num_teams']
    competition_level = data['competition_level']
    for team_name, team in teams.items():
        current_rank = team['current_rank']
        match_win_rate = team['match_wins'] / (team['match_wins'] + team['match_losses']) if (team['match_wins'] + team['match_losses']) > 0 else 0
        game_win_rate = team['game_wins'] / (team['game_wins'] + team['game_losses']) if (team['game_wins'] + team['game_losses']) > 0 else 0
        sum_mti = sum(m[0] * m[1] for m in team['successful_matches'])
        first_integral = (n**2 - current_rank**2) ** (competition_level * data['x']) * (sum_mti) ** ((match_win_rate + game_win_rate ** 2) / 2)
        team['first_integral'] = first_integral
    return data

def calculate_second_integral(data):
    teams = data['teams']
    fi = [t['first_integral'] for t in teams.values()]
    mx, mn = max(fi), min(fi)
    for team in teams.values():
        if mx == mn:
            team['second_integral'] = 500
        else:
            team['second_integral'] = 1 + (team['first_integral'] - mn) * (999 / (mx - mn))
    return data

def calculate_streak_bonus(team):
    return sum(c ** (1 + c / 5) for c in team['win_streaks_count'])

def calculate_upset_bonus(team, matches, teams):
    bonus = 0
    for match in matches:
        fs1, fs2, _ = match['scores'][0]
        if fs1 in ['-1','-2','-3'] or fs2 in ['-1','-2','-3']:
            continue
        if match['team1'] == team['name']:
            opponent = match['team2']
            tw = sum(1 for s in match['scores'] if int(s[0]) > int(s[1]))
            ow = sum(1 for s in match['scores'] if int(s[1]) > int(s[0]))
        elif match['team2'] == team['name']:
            opponent = match['team1']
            tw = sum(1 for s in match['scores'] if int(s[1]) > int(s[0]))
            ow = sum(1 for s in match['scores'] if int(s[0]) > int(s[1]))
        else:
            continue
        if team['prev_rank'] is not None and teams[opponent]['prev_rank'] is not None and tw > ow:
            diff = int(team['prev_rank']) - int(teams[opponent]['prev_rank'])
            if diff >= 8:
                bonus += 1.2 ** min(diff, 25)
    return bonus

def calculate_high_rank_win_bonus(team, matches, teams):
    bonus = 0
    for match in matches:
        fs1, fs2, _ = match['scores'][0]
        if fs1 in ['-1','-2','-3'] or fs2 in ['-1','-2','-3']:
            continue
        if match['team1'] == team['name']:
            opponent = match['team2']
            tw = sum(1 for s in match['scores'] if int(s[0]) > int(s[1]))
            ow = sum(1 for s in match['scores'] if int(s[1]) > int(s[0]))
        elif match['team2'] == team['name']:
            opponent = match['team1']
            tw = sum(1 for s in match['scores'] if int(s[1]) > int(s[0]))
            ow = sum(1 for s in match['scores'] if int(s[0]) > int(s[1]))
        else:
            continue
        if teams[opponent]['prev_rank'] is not None and int(teams[opponent]['prev_rank']) <= 6 and tw > ow:
            bonus += 10 ** (1 + 0.2 * (7 - int(teams[opponent]['prev_rank'])))
    return bonus

def calculate_total_bonus(data):
    teams = data['teams']
    matches = data['matches']
    for team_name, team in teams.items():
        team['name'] = team_name
        team['total_bonus'] = calculate_streak_bonus(team) + calculate_upset_bonus(team, matches, teams) + calculate_high_rank_win_bonus(team, matches, teams)
    return data

def calculate_third_integral(data):
    teams = data['teams']
    combined = [t['second_integral'] + t['total_bonus'] for t in teams.values()]
    mx, mn = max(combined), min(combined)
    for team in teams.values():
        c = team['second_integral'] + team['total_bonus']
        if mx == mn:
            team['third_integral'] = 500
        else:
            team['third_integral'] = 1 + (c - mn) * (999 / (mx - mn))
    return data

def calculate_fourth_integral(data):
    teams = data['teams']
    ti = [t['third_integral'] for t in teams.values()]
    median_ti = statistics.median(ti)
    mean_ti = statistics.mean(ti)
    level = data['competition_level']
    for team in teams.values():
        team['fourth_integral'] = team['third_integral'] * team['fourth_integral_weight'] * ((level * data['x']) ** 2 * mean_ti / median_ti) ** 0.25
    return data

def calculate_fifth_integral(data):
    teams = data['teams']
    for team in teams.values():
        lp = team['late_count'] * 25
        fp = team['forfeit_count'] * 50
        alp = 100 if team['late_count'] >= 3 else 0
        afp = -100 * team['forfeit_flag']
        team['fifth_integral'] = team['fourth_integral'] - lp - fp - alp - afp
    return data

def calculate_total_team_score(results, file_data):
    today = datetime.today()
    total_scores = {}
    for team_name, file_scores in results.items():
        total_score = 0
        for file_info in file_data:
            file_name = file_info['file_name']
            if file_name in file_scores:
                match_date = datetime(*file_info['date'])
                delta_days = (today - match_date).days
                competition_level = file_info['data']['competition_level']
                fifth = file_scores[file_name]
                total_score += fifth * (1 - 1 / competition_level) ** (delta_days / 50)
        total_scores[team_name] = total_score
    ranked_teams = sorted(total_scores.items(), key=lambda x: x[1], reverse=True)
    rankings = {t: i+1 for i, (t, _) in enumerate(ranked_teams)}
    return total_scores, rankings

def process_all(directory_path):
    csv_files = [f for f in os.listdir(directory_path) if f.endswith('.csv')]
    file_data = []
    for fn in csv_files:
        fp = os.path.join(directory_path, fn)
        d = parse_csv(fp)
        file_data.append({'file_name': fn, 'date': d['date'], 'data': d})
    file_data.sort(key=lambda x: x['date'])
    results = {}
    for fi in file_data:
        fn = fi['file_name']
        d = fi['data']
        d = calculate_first_integral(d)
        d = calculate_second_integral(d)
        d = calculate_total_bonus(d)
        d = calculate_third_integral(d)
        d = calculate_fourth_integral(d)
        d = calculate_fifth_integral(d)
        for tn, team in d['teams'].items():
            if tn not in results:
                results[tn] = {}
            results[tn][fn] = team['fifth_integral']
    return results, file_data

